SELECT S.AREA_INGRESSO, COUNT(S.PK_SIAPE) AS QTD_SERVIDORES FROM SERVIDOR S WHERE LOWER(S.SIGLA_CAMPUS) = LOWER('ana') AND LOWER(S.CONTRATO) = LOWER('efetivos') AND S.SAIU_DO_IFG = FALSE AND S.DATA_INGRESSO_IFG <= '2024-06-30' AND (S.DATA_INGRESSO_IFG IS NULL OR S.DATA_INGRESSO_IFG <= '2024-06-30') GROUP BY S.AREA_INGRESSO ORDER BY QTD_SERVIDORES ASC LIMIT 1